     5→export function resolveHome(): string {
     6→  if (process.platform === "win32") {
     7→    return os.homedir();
     8→  }
     9→
    10→  const sudoUser = process.env["SUDO_USER"];
    11→  if (sudoUser) {
    12→    const base = process.platform === "darwin" ? "/Users" : "/home";
    13→    return path.join(base, sudoUser);
    14→  }
    15→
    16→  return os.homedir();
    17→}
    18→
    19→export function getPlatformKey(): "posix" | "windows" {
    20→  return process.platform === "win32" ? "windows" : "posix";
    21→}
    22→
    23→export function getDeployMethod(): "symlink" | "copy" {
    24→  return process.platform === "win32" ? "copy" : "symlink";
