    15→
    16→export function planDeploy(
    17→  manifest: Manifest,
    18→  sourceDir: string,
    19→  detectedAgents: AgentId[],
    20→  home: string
    21→): DeployAction[] {
    22→  const method = getDeployMethod();
    23→  const actions: DeployAction[] = [];
    24→  const resolvedSourceDir = path.resolve(sourceDir);
    25→
    26→  for (const skill of manifest.skills) {
    27→    const source = path.resolve(sourceDir, skill.path);
    28→
    29→    if (source !== resolvedSourceDir && !source.startsWith(resolvedSourceDir + path.sep)) {
    30→      throw new UserError(
    31→        `Skill path "${skill.path}" resolves outside the repository root: ${source}`
    32→      );
    33→    }
    34→
    35→    for (const agentId of skill.agents) {
    36→      if (!detectedAgents.includes(agentId)) continue;
    37→
    38→      const agent = AGENT_REGISTRY.find((a) => a.id === agentId);
    39→      if (!agent) continue;
    40→
    41→      const target = resolveAgentSkillPath(agent, skill.name, home);
    42→
    43→      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    44→    }
    45→  }
    46→
    47→  return actions;
    48→}
    49→
    50→export function executeDeploy(
    51→  actions: DeployAction[],
    52→  dryRun: boolean,
    53→  verbose: boolean
    54→): { succeeded: number; failed: Array<{ action: DeployAction; error: string }> } {
    55→  let succeeded = 0;
    56→  const failed: Array<{ action: DeployAction; error: string }> = [];
    57→
    58→  for (const action of actions) {
    59→    const label = `${action.skill} -> ${action.agent}`;
    60→
    61→    if (!existsSync(action.source)) {
    62→      const msg = `Source not found: ${action.source}`;
    63→      failed.push({ action, error: msg });
    64→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    65→      continue;
    66→    }
    67→
    68→    if (dryRun) {
    69→      console.log(`  \x1b[36m○\x1b[0m ${label}`);
    70→      if (verbose) {
    71→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    72→      }
    73→      succeeded++;
    74→      continue;
    75→    }
    76→
    77→    try {
    78→      removeExisting(action.target, verbose);
    79→      mkdirSync(path.dirname(action.target), { recursive: true });
    80→
    81→      if (action.method === "symlink") {
    82→        symlinkSync(action.source, action.target, "dir");
    83→      } else {
    84→        cpSync(action.source, action.target, { recursive: true });
    85→      }
    86→
    87→      console.log(`  \x1b[32m✓\x1b[0m ${label}`);
    88→      if (verbose) {
    89→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    90→      }
    91→      succeeded++;
    92→    } catch (err) {
    93→      const msg = err instanceof Error ? err.message : String(err);
    94→      failed.push({ action, error: msg });
    95→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    96→    }
    97→  }
    98→
    99→  return { succeeded, failed };
   100→}
   101→
   102→function removeExisting(targetPath: string, verbose: boolean): void {
   103→  if (!existsSync(targetPath) && !isSymlink(targetPath)) return;
   104→
   105→  if (isSymlink(targetPath)) {
   106→    if (verbose) {
   107→      console.log(`    removing existing symlink: ${targetPath}`);
