     1→#!/usr/bin/env node
     2→
     3→import path from "node:path";
     4→import { AGENT_IDS } from "./types.ts";
     5→import type { AgentId, CliOptions } from "./types.ts";
     6→import { loadManifest } from "./config/manifest.ts";
     7→import { AGENT_REGISTRY } from "./config/agents.ts";
     8→import { resolveHome } from "./core/resolve.ts";
     9→import { detectInstalledAgents } from "./core/detect.ts";
    10→import { planDeploy, executeDeploy } from "./core/deploy.ts";
    11→import { planRevert, executeRevert } from "./core/revert.ts";
    12→import { UserError } from "./errors.ts";
    13→
    14→const USAGE = `
    15→inception-engine - Deploy AI agent skills
    16→
    17→Usage:
    18→  inception-engine <directory> [options]
    19→  inception-engine revert <directory> [options]
    20→
    21→Options:
    22→  --dry-run        Show what would be done without doing it
    23→  --agents <list>  Comma-separated list of agent IDs to target
    24→  --verbose        Show detailed output
    25→  --debug          Show full error stack traces
    26→  --help           Show this help message
    27→
    28→Supported agents:
    29→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
    30→`.trim();
    31→
    32→function parseArgs(argv: string[]): CliOptions {
    33→  const args = argv.slice(2);
    34→
    35→  if (args.length === 0 || args.includes("--help")) {
    36→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false, debug: false };
    37→  }
    38→
    39→  let command: "deploy" | "revert" = "deploy";
    40→  let directory = "";
    41→  let dryRun = false;
    42→  let agents: AgentId[] | null = null;
    43→  let verbose = false;
    44→  let debug = false;
    45→
    46→  let i = 0;
    47→  if (args[0] === "revert") {
    48→    command = "revert";
    49→    i = 1;
    50→  }
    51→
    52→  while (i < args.length) {
    53→    const arg = args[i]!;
    54→
    55→    if (arg === "--dry-run") {
    56→      dryRun = true;
    57→    } else if (arg === "--verbose") {
    58→      verbose = true;
    59→    } else if (arg === "--debug") {
    60→      debug = true;
    61→    } else if (arg === "--agents") {
    62→      i++;
    63→      const next = args[i];
    64→      if (!next) {
    65→        throw new UserError("--agents requires a comma-separated list");
    66→      }
    67→      const ids = next.split(",").map((s) => s.trim());
    68→      for (const id of ids) {
    69→        if (!AGENT_IDS.includes(id as AgentId)) {
    70→          throw new UserError(`Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`);
    71→        }
    72→      }
    73→      agents = ids as AgentId[];
    74→    } else if (arg.startsWith("--")) {
    75→      throw new UserError(`Unknown option: ${arg}`);
    76→    } else if (!directory) {
    77→      directory = arg;
    78→    } else {
    79→      throw new UserError(`Unexpected argument: ${arg}`);
    80→    }
    81→    i++;
    82→  }
    83→
    84→  if (!directory) {
    85→    throw new UserError("Missing required <directory> argument");
    86→  }
    87→
    88→  return { command, directory: path.resolve(directory), dryRun, agents, verbose, debug };
    89→}
    90→
    91→function main(): number {
    92→  const options = parseArgs(process.argv);
    93→
    94→  if (options.command === "help") {
    95→    console.log(USAGE);
    96→    return 0;
    97→  }
    98→
    99→  const manifest = loadManifest(options.directory);
   100→  const home = resolveHome();
   101→
   102→  let detectedAgents: AgentId[];
   103→  if (options.agents) {
   104→    detectedAgents = options.agents;
   105→    if (options.verbose) {
   106→      console.log(`Using specified agents: ${detectedAgents.join(", ")}`);
   107→    }
   108→  } else {
   109→    detectedAgents = detectInstalledAgents(home);
   110→    if (detectedAgents.length === 0) {
   111→      console.log("No supported AI agents detected on this system.");
   112→      console.log(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
   113→      return 0;
   114→    }
   115→    if (options.verbose) {
   116→      console.log(`Detected agents: ${detectedAgents.join(", ")}`);
   117→    }
   118→  }
   119→
   120→  const prefix = options.dryRun ? "\x1b[36m[dry-run]\x1b[0m " : "";
   121→
   122→  if (options.command === "deploy") {
   123→    const actions = planDeploy(manifest, options.directory, detectedAgents, home);
   124→    if (actions.length === 0) {
   125→      console.log("No skills to deploy for detected agents.");
   126→      return 0;
   127→    }
   128→
   129→    console.log(`${prefix}Deploying ${actions.length} skill(s):`);
   130→    const { succeeded, failed } = executeDeploy(actions, options.dryRun, options.verbose);
   131→
   132→    console.log();
   133→    if (failed.length > 0) {
   134→      console.log(`${succeeded} succeeded, ${failed.length} failed`);
   135→      return 1;
   136→    } else {
   137→      console.log(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
   138→    }
   139→  } else {
   140→    const actions = planRevert(manifest, detectedAgents, home);
   141→    if (actions.length === 0) {
   142→      console.log("No skills to revert for detected agents.");
   143→      return 0;
   144→    }
   145→
   146→    console.log(`${prefix}Reverting ${actions.length} skill(s):`);
   147→    const { succeeded, skipped } = executeRevert(actions, options.dryRun, options.verbose);
   148→
   149→    console.log();
   150→    const parts = [`${succeeded} removed`];
   151→    if (skipped > 0) parts.push(`${skipped} skipped`);
   152→    console.log(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
   153→  }
   154→
   155→  return 0;
   156→}
   157→
   158→const debugMode = process.argv.includes("--debug");
   159→
   160→try {
   161→  process.exit(main());
   162→} catch (err) {
   163→  if (err instanceof UserError) {
   164→    console.error(`Error: ${err.message}`);
   165→  } else {
   166→    console.error("Unexpected error. Run with --debug for details.");
   167→  }
   168→  if (debugMode) {
   169→    console.error(err);
   170→  }
   171→  process.exit(1);
   172→}
